body:
On verilator 4.224 as well as master branch

The following code:
```verilog
module tjo();

function automatic string broken_case(input string some_string);
    case(some_string)
        "foo": return "foo";
        default: return "bar";
    endcase
endfunction

initial begin
    $display(broken_case("baz"));
end
endmodule
```

Generate code that will not compile. The error is: 
```
Vtjo___024root__DepSet_h3395a8d1__0__Slow.cpp: In function ‘void Vtjo___024root___initial__TOP__0(Vtjo___024root*)’:
Vtjo___024root__DepSet_h3395a8d1__0__Slow.cpp:21:30: error: no match for ‘operator==’ (operand types are ‘long long unsigned int’ and ‘std::string’ {aka ‘std::__cxx11::basic_string<char>’})
   21 |             if ((0x666f6fULL == __Vfunc_tjo__DOT__broken_case__0__some_string)) {
      |                  ~~~~~~~~~~~ ^~ ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
      |                  |              |
      |                  |              std::string {aka std::__cxx11::basic_string<char>}
      |                  long long unsigned int
```


The generated code looks like this: 

```cpp
VL_ATTR_COLD void Vtjo___024root___initial__TOP__0(Vtjo___024root* vlSelf) {
    if (false && vlSelf) {}  // Prevent unused
    Vtjo__Syms* const __restrict vlSymsp VL_ATTR_UNUSED = vlSelf->vlSymsp;
    VL_DEBUG_IF(VL_DBG_MSGF("+    Vtjo___024root___initial__TOP__0\n"); );
    // Init
    std::string __Vfunc_tjo__DOT__broken_case__0__Vfuncout;
    std::string __Vfunc_tjo__DOT__broken_case__0__some_string;
    // Body
    __Vfunc_tjo__DOT__broken_case__0__some_string = 
        std::string("baz");
    {
        {
            if ((0x666f6fULL == __Vfunc_tjo__DOT__broken_case__0__some_string)) {
                __Vfunc_tjo__DOT__broken_case__0__Vfuncout = 
                    std::string("foo");
                goto __Vlabel2;
            } else {
                __Vfunc_tjo__DOT__broken_case__0__Vfuncout = 
                    std::string("bar");
                goto __Vlabel1;
            }
            __Vlabel2: ;
        }
        __Vlabel1: ;
    }
    VL_WRITEF("%@\n",-1,&(__Vfunc_tjo__DOT__broken_case__0__Vfuncout));
}
```

The broken part
```cpp
            if ((0x666f6fULL == __Vfunc_tjo__DOT__broken_case__0__some_string)) {
```

It looks like string literals are incorrectly converted to `unsigned long long` instead of `std::string`. A verilog string is correctly converted to a `std::string`.

I am not sure where in the code this conversion is done. With some pointers I can help create a fix for this, if it is not too complex.
